// Robot Buddy — a friendly retro desktop robot.
// BREP showcase: box torso + feet, cone head, horizontal cylindrical arms,
// stubby antenna + ball on top, eye spheres on the front of the head, and
// a thin chest-panel bump on the torso.
const { BREP } = api;

// ---- Feet (two boxes sitting on the ground) ----
const footW = 7, footD = 9, footH = 5;
const footL = BREP.box([footW, footD, footH]).translate([-7, 0, 0]);
const footR = BREP.box([footW, footD, footH]).translate([+7, 0, 0]);

// ---- Torso (boxy body, on top of the feet) ----
const torsoW = 25, torsoD = 18, torsoH = 22;
const torsoZ0 = footH; // 5
const torso = BREP.box([torsoW, torsoD, torsoH]).translate([0, 0, torsoZ0]);

// ---- Arms (stubby horizontal cylinders) ----
// BREP.cylinder is axis-Z by default; rotate ±90° around Y to make it
// horizontal so it sticks out to ±X.
const armR = 3, armLen = 8;
const armZ = torsoZ0 + 14;
const armProto = BREP.cylinder(armR, armLen);
const armRight = armProto.rotate(-90, [0, 1, 0]).translate([torsoW / 2, 0, armZ]);
const armLeft  = armProto.rotate(+90, [0, 1, 0]).translate([-torsoW / 2, 0, armZ]);

// ---- Head (truncated cone — friendly retro silhouette) ----
const headRBottom = 12, headRTop = 8, headH = 10;
const headZ0 = torsoZ0 + torsoH; // 27
const head = BREP.cone(headRBottom, headRTop, headH).translate([0, 0, headZ0]);

// ---- Eyes (two small spheres on the +Y face of the head) ----
const eyeR = 1.8;
const eyeZ = headZ0 + headH * 0.55; // 32.5
// At eyeZ in the cone, the surface radius is:
//   rB + (rT - rB) * (eyeZ - z0) / h
const headRAtEye = headRBottom + (headRTop - headRBottom) * (eyeZ - headZ0) / headH;
const eyeY = headRAtEye - 0.5; // slightly inset into the +Y face
const eyeRight = BREP.sphere(eyeR).translate([+3.5, eyeY, eyeZ]);
const eyeLeft  = BREP.sphere(eyeR).translate([-3.5, eyeY, eyeZ]);

// ---- Chest panel (thin box bumped out of the torso +Y face) ----
const panelW = 14, panelD = 1.2, panelH = 10;
const panelZ = torsoZ0 + (torsoH - panelH) / 2;
const panel = BREP.box([panelW, panelD, panelH]).translate(
  [0, torsoD / 2, panelZ],
);

// ---- Antenna (thin rod + small ball on top) ----
const antennaR = 0.6, antennaH = 9;
const antennaZ0 = headZ0 + headH + 0.5; // 37.5 — small gap above head
const antennaRod = BREP.cylinder(antennaR, antennaH).translate([0, 0, antennaZ0]);
const antennaBall = BREP.sphere(1.6).translate([0, 0, antennaZ0 + antennaH + 0.6]);

// ---- Assemble ----
return BREP.fuseAll([
  footL, footR,
  torso,
  armLeft, armRight,
  head,
  eyeLeft, eyeRight,
  panel,
  antennaRod, antennaBall,
]);

